using System.Net.Http.Json;
using SiteInspector.Shared.Models;

namespace SiteInspector.Client.Services;

public class SyncService : IDisposable
{
    private readonly ILocalStore _store;
    private readonly HttpClient _http;
    private readonly ConnectivityService _connectivity;
    private Timer? _timer;
    public event Action<string>? OnSyncStatusChanged;
    public string LastSyncStatus { get; private set; } = "Not synced";

    public SyncService(ILocalStore store, HttpClient http, ConnectivityService connectivity)
    {
        _store = store;
        _http = http;
        _connectivity = connectivity;
    }

    public void Start()
    {
        _connectivity.OnConnectivityChanged += OnConnectivityChanged;
        _timer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    private async void OnConnectivityChanged()
    {
        if (_connectivity.IsOnline)
        {
            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        if (!_connectivity.IsOnline) return;

        try
        {
            var unsynced = await _store.GetUnsyncedInspectionsAsync();
            if (unsynced.Count == 0)
            {
                LastSyncStatus = "All data synced";
                OnSyncStatusChanged?.Invoke(LastSyncStatus);
                return;
            }

            var sites = await _store.GetAllSitesAsync();
            var relevantSiteIds = unsynced.Select(i => i.SiteId).Distinct().ToHashSet();
            var relevantSites = sites.Where(s => relevantSiteIds.Contains(s.Id)).ToList();

            var payload = new SyncPayload
            {
                Sites = relevantSites,
                Inspections = unsynced
            };

            var response = await _http.PostAsJsonAsync("api/sync", payload);
            if (response.IsSuccessStatusCode)
            {
                var result = await response.Content.ReadFromJsonAsync<SyncResult>();
                if (result?.Success == true)
                {
                    await _store.MarkAsSyncedAsync(unsynced.Select(i => i.Id));
                    LastSyncStatus = $"Synced {result.InspectionsSynced} inspection(s) at {DateTimeOffset.Now:HH:mm}";
                }
                else
                {
                    LastSyncStatus = $"Sync error: {result?.Error ?? "Unknown"}";
                }
            }
            else
            {
                LastSyncStatus = $"Sync failed: {response.StatusCode}";
            }
        }
        catch (Exception ex)
        {
            LastSyncStatus = $"Sync unavailable: {ex.Message}";
        }

        OnSyncStatusChanged?.Invoke(LastSyncStatus);
    }

    public void Dispose()
    {
        _connectivity.OnConnectivityChanged -= OnConnectivityChanged;
        _timer?.Dispose();
    }
}

const DB_NAME = 'SiteInspectorDb';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('isSynced', 'isSynced', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbStore = {
    putItem: async function (storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).put(item);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).get(id);
            request.onsuccess = () => resolve(request.result || null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllItems: async function (storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).getAll();
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getItemsByIndex: async function (storeName, indexName, value) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const index = tx.objectStore(storeName).index(indexName);
            const request = index.getAll(value);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).delete(id);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedInspections: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction('inspections', 'readonly');
            const index = tx.objectStore('inspections').index('isSynced');
            const request = index.getAll(false);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    markAsSynced: async function (ids) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction('inspections', 'readwrite');
            const store = tx.objectStore('inspections');
            for (const id of ids) {
                const req = store.get(id);
                req.onsuccess = () => {
                    const item = req.result;
                    if (item) {
                        item.isSynced = true;
                        store.put(item);
                    }
                };
            }
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    }
};

