    {
        var json = Serialize(site);
        await _js.InvokeVoidAsync("indexedDbStore.putItem", "sites", json);
    }

    public async Task DeleteSiteAsync(string id) =>
        await _js.InvokeVoidAsync("indexedDbStore.deleteItem", "sites", id);

