        await _js.InvokeVoidAsync("indexedDbStore.deleteItem", "inspections", id);

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDbStore.getUnsyncedInspections");
        return Deserialize<List<Inspection>>(items) ?? [];
    }

    public async Task MarkAsSyncedAsync(IEnumerable<string> ids) =>
        await _js.InvokeVoidAsync("indexedDbStore.markAsSynced", ids.ToArray());

