@inherits LayoutComponentBase
@inject ConnectivityService Connectivity
@inject SyncService Sync

<div class="app-container">
    <header class="app-header">
        <div class="header-left">
            <a href="/" class="header-title">🏗️ Site Inspector</a>
        </div>
        <div class="header-right">
            <span class="connectivity-badge @(Connectivity.IsOnline ? "online" : "offline")">
                @(Connectivity.IsOnline ? "●" : "○") @(Connectivity.IsOnline ? "Online" : "Offline")
            </span>
        </div>
    </header>

    <main class="app-main">
        @Body
    </main>

    <footer class="app-footer">
        <span class="sync-status">@_syncStatus</span>
    </footer>
</div>

@code {
    private string _syncStatus = "Not synced";

    protected override void OnInitialized()
    {
        Sync.OnSyncStatusChanged += HandleSyncStatusChanged;
        _syncStatus = Sync.LastSyncStatus;
    }

    private void HandleSyncStatusChanged(string status)
    {
        _syncStatus = status;
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Sync.OnSyncStatusChanged -= HandleSyncStatusChanged;
    }
}

@page "/site/{SiteId}"
@inject ILocalStore Store
@inject NavigationManager Nav

<PageTitle>Site Detail - Site Inspector</PageTitle>

@if (_site == null)
{
    <p class="loading">Loading...</p>
}
else
{
    <div class="page-header">
        <div>
            <a href="/" class="back-link">← Sites</a>
            <h1>@_site.Name</h1>
            <p class="subtitle">@_site.Address</p>
        </div>
        <button class="btn btn-primary" @onclick="StartInspection">+ Inspect</button>
    </div>

    @if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <p>No inspections recorded yet.</p>
            <p>Tap <strong>+ Inspect</strong> to begin a safety inspection.</p>
        </div>
    }
    else
    {
        <div class="inspection-list">
            @foreach (var inspection in _inspections.OrderByDescending(i => i.InspectedAt))
            {
                <div class="card inspection-card" @onclick="() => Nav.NavigateTo($"/inspection/{inspection.Id}")">
                    <div class="inspection-card-content">
                        <div class="inspection-date">@inspection.InspectedAt.LocalDateTime.ToString("dd MMM yyyy HH:mm")</div>
                        <div class="inspection-inspector">@inspection.InspectorName</div>
                        <div class="inspection-stats">
                            <span class="stat pass">✓ @inspection.Checklist.Count(c => c.Result == CheckResult.Pass)</span>
                            <span class="stat fail">✗ @inspection.Checklist.Count(c => c.Result == CheckResult.Fail)</span>
                            <span class="stat photos">📷 @inspection.Photos.Count</span>
                        </div>
                    </div>
                    <div class="card-right">
                        <span class="sync-indicator @(inspection.IsSynced ? "synced" : "pending")">
                            @(inspection.IsSynced ? "✓" : "⟳")
                        </span>
                        <span class="chevron">›</span>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private ConstructionSite? _site;
    private List<Inspection> _inspections = [];

    protected override async Task OnInitializedAsync()
    {
        _site = await Store.GetSiteAsync(SiteId);
        _inspections = await Store.GetInspectionsForSiteAsync(SiteId);
    }

    private void StartInspection()
    {
        Nav.NavigateTo($"/inspect/{SiteId}");
    }
}

@page "/inspect/{SiteId}"
@inject ILocalStore Store
@inject NavigationManager Nav
@inject IJSRuntime JS

<PageTitle>New Inspection - Site Inspector</PageTitle>

<div class="page-header compact">
    <a href="/site/@SiteId" class="back-link">← Back</a>
    <h1>Safety Inspection</h1>
</div>

@if (!_started)
{
    <div class="card start-form">
        <label class="label">Inspector Name</label>
        <input class="input" @bind="_inspectorName" @bind:event="oninput" placeholder="Your name" />
        <button class="btn btn-primary btn-block" @onclick="BeginInspection"
                disabled="@(string.IsNullOrWhiteSpace(_inspectorName))">
            Begin Inspection
        </button>
    </div>
}
else
{
    <div class="checklist-progress">
        <div class="progress-bar">
            <div class="progress-fill" style="width: @(ProgressPercent)%"></div>
        </div>
        <span class="progress-text">@_checkedCount / @_inspection!.Checklist.Count</span>
    </div>

    <!-- Category tabs -->
    <div class="category-tabs">
        @foreach (var cat in _categories)
        {
            <button class="tab @(cat == _activeCategory ? "active" : "")" @onclick="() => _activeCategory = cat">
                @cat.Split(' ').Last()
            </button>
        }
    </div>

    <!-- Checklist items for active category -->
    <div class="checklist">
        @foreach (var item in _inspection!.Checklist.Where(c => c.Category == _activeCategory))
        {
            <div class="checklist-item @item.Result.ToString().ToLower()">
                <div class="checklist-desc">@item.Description</div>
                <div class="checklist-actions">
                    <button class="check-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                            @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                    <button class="check-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                            @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                    <button class="check-btn na @(item.Result == CheckResult.NotApplicable ? "selected" : "")"
                            @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                </div>
                @if (item.Result == CheckResult.Fail)
                {
                    <input class="input note-input" placeholder="Note (required for failures)"
                           value="@item.Notes" @oninput="(e) => item.Notes = e.Value?.ToString() ?? string.Empty" />
                }
            </div>
        }
    </div>

    <!-- Notes section -->
    <div class="section">
        <h2>General Notes</h2>
        <textarea class="input textarea" rows="3" placeholder="Additional observations..."
                  @bind="_inspection.Notes" @bind:event="oninput"></textarea>
    </div>

    <!-- Photos section -->
    <div class="section">
        <h2>Photos (@_inspection.Photos.Count)</h2>
        <label class="btn btn-secondary photo-btn">
            📷 Add Photo
            <InputFile OnChange="HandlePhotoSelected" accept="image/*" capture="environment" style="display:none" />
        </label>

        @if (_inspection.Photos.Count > 0)
        {
            <div class="photo-grid">
                @foreach (var photo in _inspection.Photos)
                {
                    <div class="photo-thumb">
                        <img src="data:@photo.ContentType;base64,@photo.Base64Data" alt="@photo.Caption" />
                        <button class="photo-remove" @onclick="() => RemovePhoto(photo)">×</button>
                    </div>
                }
            </div>
        }
    </div>

    <!-- Submit -->
    <div class="form-actions sticky-bottom">
        <button class="btn btn-secondary" @onclick="SaveDraft">Save Draft</button>
        <button class="btn btn-primary" @onclick="CompleteInspection">Complete Inspection</button>
    </div>
}

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private Inspection? _inspection;
    private bool _started;
    private string _inspectorName = "";
    private string[] _categories = [];
    private string _activeCategory = "";
    private int _checkedCount => _inspection?.Checklist.Count(c => c.Result != CheckResult.NotChecked) ?? 0;
    private int ProgressPercent => _inspection?.Checklist.Count > 0
        ? (int)((double)_checkedCount / _inspection.Checklist.Count * 100) : 0;

    private void BeginInspection()
    {
        _inspection = new Inspection
        {
            SiteId = SiteId,
            InspectorName = _inspectorName.Trim(),
            Checklist = ChecklistTemplate.GetDefaultChecklist()
        };
        _categories = _inspection.Checklist.Select(c => c.Category).Distinct().ToArray();
        _activeCategory = _categories.First();
        _started = true;
    }

    private void SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = result;
        if (result != CheckResult.Fail)
            item.Notes = "";
    }

    private async Task HandlePhotoSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(5))
        {
            if (file.Size > 10 * 1024 * 1024) continue; // Skip files > 10MB

            using var stream = file.OpenReadStream(10 * 1024 * 1024);
            using var ms = new MemoryStream();
            await stream.CopyToAsync(ms);

            var photo = new InspectionPhoto
            {
                FileName = file.Name,
                ContentType = file.ContentType,
                Base64Data = Convert.ToBase64String(ms.ToArray()),
                TakenAt = DateTimeOffset.Now
            };

            _inspection!.Photos.Add(photo);
        }
    }

    private void RemovePhoto(InspectionPhoto photo)
    {
        _inspection!.Photos.Remove(photo);
    }

    private async Task SaveDraft()
    {
        if (_inspection == null) return;
        _inspection.Status = InspectionStatus.InProgress;
        await Store.SaveInspectionAsync(_inspection);
        Nav.NavigateTo($"/site/{SiteId}");
    }

    private async Task CompleteInspection()
    {
        if (_inspection == null) return;
        _inspection.Status = InspectionStatus.Completed;
        _inspection.InspectedAt = DateTimeOffset.Now;
        await Store.SaveInspectionAsync(_inspection);
        Nav.NavigateTo($"/site/{SiteId}");
    }
}

