+    private void BeginInspection()
+    {
+        _inspection = new Inspection
+        {
+            SiteId = SiteId,
+            InspectorName = _inspectorName.Trim(),
+            Checklist = ChecklistTemplate.GetDefaultChecklist()
+        };
+        _categories = _inspection.Checklist.Select(c => c.Category).Distinct().ToArray();
+        _activeCategory = _categories.First();
+        _started = true;
+    }
+
+    private void SetResult(ChecklistItem item, CheckResult result)
+    {
+        item.Result = result;
+        if (result != CheckResult.Fail)
+            item.Notes = "";
+    }
+
+    private async Task HandlePhotoSelected(InputFileChangeEventArgs e)
+    {
+        foreach (var file in e.GetMultipleFiles(5))
+        {
+            if (file.Size > 10 * 1024 * 1024) continue; // Skip files > 10MB
+
+            using var stream = file.OpenReadStream(10 * 1024 * 1024);
+            using var ms = new MemoryStream();
+            await stream.CopyToAsync(ms);
+
+            var photo = new InspectionPhoto
+            {
+                FileName = file.Name,
+                ContentType = file.ContentType,
+                Base64Data = Convert.ToBase64String(ms.ToArray()),
+                TakenAt = DateTimeOffset.Now
+            };
+
+            _inspection!.Photos.Add(photo);
+        }
+    }
+
+    private void RemovePhoto(InspectionPhoto photo)
+    {
+        _inspection!.Photos.Remove(photo);
+    }
+
+    private async Task SaveDraft()
+    {
+        if (_inspection == null) return;
+        _inspection.Status = InspectionStatus.InProgress;
+        await Store.SaveInspectionAsync(_inspection);
+        Nav.NavigateTo($"/site/{SiteId}");
+    }
+
+    private async Task CompleteInspection()
+    {
+        if (_inspection == null) return;
+        _inspection.Status = InspectionStatus.Completed;
+        _inspection.InspectedAt = DateTimeOffset.Now;
+        await Store.SaveInspectionAsync(_inspection);
+        Nav.NavigateTo($"/site/{SiteId}");
+    }
+}
+

toolArgs.file_text:
@page "/inspection/{InspectionId}"
@inject ILocalStore Store
@inject NavigationManager Nav

<PageTitle>Inspection Detail - Site Inspector</PageTitle>

@if (_inspection == null)
{
    <p class="loading">Loading...</p>
}
else
{
    <div class="page-header compact">
        <a href="/site/@_inspection.SiteId" class="back-link">← Back</a>
        <h1>Inspection Report</h1>
    </div>

    <div class="card">
        <div class="detail-row">
            <span class="label">Inspector</span>
            <span>@_inspection.InspectorName</span>
        </div>
        <div class="detail-row">
            <span class="label">Date</span>
            <span>@_inspection.InspectedAt.LocalDateTime.ToString("dd MMM yyyy HH:mm")</span>
        </div>
        <div class="detail-row">
            <span class="label">Status</span>
            <span class="badge @_inspection.Status.ToString().ToLower()">@_inspection.Status</span>
        </div>
        <div class="detail-row">
            <span class="label">Synced</span>
            <span>@(_inspection.IsSynced ? "✓ Yes" : "⟳ Pending")</span>
        </div>
    </div>

    <!-- Summary stats -->
    <div class="stats-grid">
        <div class="stat-card pass">
            <div class="stat-number">@_inspection.Checklist.Count(c => c.Result == CheckResult.Pass)</div>
            <div class="stat-label">Pass</div>
        </div>
        <div class="stat-card fail">
            <div class="stat-number">@_inspection.Checklist.Count(c => c.Result == CheckResult.Fail)</div>
            <div class="stat-label">Fail</div>
        </div>
        <div class="stat-card na">
            <div class="stat-number">@_inspection.Checklist.Count(c => c.Result == CheckResult.NotApplicable)</div>
            <div class="stat-label">N/A</div>
        </div>
        <div class="stat-card unchecked">
            <div class="stat-number">@_inspection.Checklist.Count(c => c.Result == CheckResult.NotChecked)</div>
            <div class="stat-label">Unchecked</div>
        </div>
    </div>

    <!-- Failed items -->
    @{ var failures = _inspection.Checklist.Where(c => c.Result == CheckResult.Fail).ToList(); }
    @if (failures.Count > 0)
    {
        <div class="section">
            <h2>⚠️ Failed Items</h2>
            @foreach (var item in failures)
            {
                <div class="card failure-card">
                    <div class="failure-category">@item.Category</div>
                    <div class="failure-desc">@item.Description</div>
                    @if (!string.IsNullOrEmpty(item.Notes))
                    {
                        <div class="failure-notes">📝 @item.Notes</div>
                    }
                </div>
            }
        </div>
    }

    <!-- General notes -->
    @if (!string.IsNullOrWhiteSpace(_inspection.Notes))
    {
        <div class="section">
            <h2>Notes</h2>
            <div class="card notes-card">@_inspection.Notes</div>
        </div>
    }

    <!-- Photos -->
    @if (_inspection.Photos.Count > 0)
    {
        <div class="section">
            <h2>Photos (@_inspection.Photos.Count)</h2>
            <div class="photo-grid large">
                @foreach (var photo in _inspection.Photos)
                {
                    <div class="photo-item">
                        <img src="data:@photo.ContentType;base64,@photo.Base64Data" alt="@photo.Caption" />
                        @if (!string.IsNullOrEmpty(photo.Caption))
                        {
                            <div class="photo-caption">@photo.Caption</div>
                        }
                    </div>
                }
            </div>
        </div>
    }

    <!-- Full checklist -->
    <details class="section">
        <summary><h2 style="display:inline">Full Checklist</h2></summary>
        @foreach (var category in _inspection.Checklist.GroupBy(c => c.Category))
        {
            <h3 class="category-heading">@category.Key</h3>
            @foreach (var item in category)
            {
                <div class="checklist-result-item @item.Result.ToString().ToLower()">
                    <span class="result-icon">
                        @(item.Result switch {
                            CheckResult.Pass => "✓",
                            CheckResult.Fail => "✗",
                            CheckResult.NotApplicable => "—",
                            _ => "○"
                        })
                    </span>
                    <span>@item.Description</span>
                </div>
            }
        }
    </details>
}

@code {
    [Parameter] public string InspectionId { get; set; } = "";
    private Inspection? _inspection;

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Store.GetInspectionAsync(InspectionId);
    }
}

