    align-items: center;
    justify-content: center;
    height: 100dvh;
    gap: 16px;
}
.loading-icon { font-size: 3rem; }
.loading-text { color: var(--text-muted); }
.loading { text-align: center; padding: 40px; color: var(--text-muted); }

