h1 { font-size: 1.4rem; font-weight: 700; }
h2 { font-size: 1.1rem; font-weight: 600; margin-bottom: 8px; }
h3 { font-size: 0.95rem; font-weight: 600; }

.subtitle { font-size: 0.85rem; color: var(--text-muted); }
.back-link { color: var(--primary); text-decoration: none; font-size: 0.85rem; font-weight: 500; }

