.input {
    width: 100%;
    padding: 12px;
    border: 1.5px solid var(--border);
    border-radius: 8px;
    font-size: 1rem;
    outline: none;
    transition: border-color 0.15s;
    background: var(--surface);
    min-height: 44px;
}
.input:focus { border-color: var(--primary); }
.textarea { resize: vertical; min-height: 80px; }
.note-input { margin-top: 8px; font-size: 0.85rem; padding: 8px; }
.label { font-size: 0.85rem; font-weight: 600; margin-bottom: 4px; display: block; color: var(--text-muted); }

/* === Cards === */
.card {
    background: var(--surface);
    border-radius: var(--radius);
    padding: 16px;
    box-shadow: var(--shadow);
    margin-bottom: 12px;
}

.site-card, .inspection-card {
    display: flex;
    align-items: center;
    cursor: pointer;
    transition: background 0.15s;
}
.site-card:active, .inspection-card:active { background: var(--bg); }
.site-card-content, .inspection-card-content { flex: 1; }
.site-address { font-size: 0.85rem; color: var(--text-muted); margin-top: 2px; }
.chevron { font-size: 1.4rem; color: var(--text-muted); margin-left: 8px; }

/* === Inspection Cards === */
.inspection-date { font-weight: 600; font-size: 0.9rem; }
.inspection-inspector { font-size: 0.8rem; color: var(--text-muted); }
.inspection-stats { display: flex; gap: 12px; margin-top: 4px; font-size: 0.8rem; }
.stat.pass { color: var(--success); }
.stat.fail { color: var(--danger); }
.stat.photos { color: var(--text-muted); }

.card-right { display: flex; align-items: center; gap: 4px; }
.sync-indicator { font-size: 0.8rem; }
.sync-indicator.synced { color: var(--success); }
.sync-indicator.pending { color: var(--warning); }

/* === Add Form === */
.add-form { display: flex; flex-direction: column; gap: 10px; }
.start-form { display: flex; flex-direction: column; gap: 12px; }
.form-actions { display: flex; gap: 8px; justify-content: flex-end; }

/* === Empty State === */
.empty-state {
    text-align: center;
    padding: 40px 20px;
    color: var(--text-muted);
}

