.checklist-progress { margin-bottom: 16px; }
.progress-bar {
    height: 6px;
    background: var(--border);
    border-radius: 3px;
    overflow: hidden;
}
.progress-fill {
    height: 100%;
    background: var(--primary);
    transition: width 0.2s ease;
}
.progress-text { font-size: 0.8rem; color: var(--text-muted); margin-top: 4px; }

/* === Category Tabs === */
.category-tabs {
    display: flex;
    gap: 6px;
    overflow-x: auto;
    padding-bottom: 12px;
    margin-bottom: 12px;
    -webkit-overflow-scrolling: touch;
    scrollbar-width: none;
}
.category-tabs::-webkit-scrollbar { display: none; }

.tab {
    padding: 8px 12px;
    border: none;
    border-radius: 20px;
    font-size: 0.8rem;
    font-weight: 500;
    white-space: nowrap;
    background: var(--border);
    color: var(--text);
    cursor: pointer;
    min-height: 36px;
    touch-action: manipulation;
}
.tab.active { background: var(--primary); color: white; }

