.checklist-item {
    background: var(--surface);
    border-radius: var(--radius);
    padding: 12px;
    margin-bottom: 8px;
    box-shadow: var(--shadow);
    border-left: 4px solid var(--border);
}
.checklist-item.pass { border-left-color: var(--success); }
.checklist-item.fail { border-left-color: var(--danger); }
.checklist-item.notapplicable { border-left-color: var(--neutral); }

.checklist-desc { font-size: 0.9rem; margin-bottom: 8px; }

.checklist-actions { display: flex; gap: 8px; }

.check-btn {
    width: 44px;
    height: 44px;
    border: 2px solid var(--border);
    border-radius: 8px;
    font-size: 1.1rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--surface);
    transition: all 0.1s;
    touch-action: manipulation;
}
.check-btn:active { transform: scale(0.93); }
.check-btn.pass.selected { background: var(--success); color: white; border-color: var(--success); }
.check-btn.fail.selected { background: var(--danger); color: white; border-color: var(--danger); }
.check-btn.na.selected { background: var(--neutral); color: white; border-color: var(--neutral); }

/* === Photos === */
.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
    gap: 8px;
    margin-top: 12px;
}
.photo-grid.large { grid-template-columns: repeat(auto-fill, minmax(140px, 1fr)); }

.photo-thumb, .photo-item {
    position: relative;
    border-radius: 8px;
    overflow: hidden;
    aspect-ratio: 1;
}
.photo-thumb img, .photo-item img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}
.photo-remove {
    position: absolute;
    top: 4px;
    right: 4px;
    width: 24px;
    height: 24px;
    border-radius: 50%;
    background: var(--danger);
    color: white;
    border: none;
    font-size: 1rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
}
.photo-caption {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    padding: 4px 8px;
    background: rgba(0,0,0,0.6);
    color: white;
    font-size: 0.75rem;
}

/* === Section === */
.section { margin-top: 20px; }

/* === Sticky bottom === */
.sticky-bottom {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    padding: 12px 16px;
    padding-bottom: calc(12px + var(--safe-bottom));
    background: var(--surface);
    border-top: 1px solid var(--border);
    display: flex;
    gap: 8px;
    z-index: 80;
}
.sticky-bottom .btn { flex: 1; }

/* === Detail View === */
.detail-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 8px 0;
    border-bottom: 1px solid var(--border);
}
.detail-row:last-child { border-bottom: none; }
.detail-row .label { margin-bottom: 0; }

.badge {
    padding: 4px 8px;
    border-radius: 12px;
    font-size: 0.75rem;
    font-weight: 600;
}
.badge.completed { background: #dcfce7; color: var(--success); }
.badge.inprogress { background: #fef3c7; color: var(--warning); }

/* === Stats Grid === */
.stats-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 8px;
    margin: 16px 0;
}
.stat-card {
    background: var(--surface);
    border-radius: var(--radius);
    padding: 12px 8px;
    text-align: center;
    box-shadow: var(--shadow);
}
.stat-number { font-size: 1.5rem; font-weight: 700; }
.stat-label { font-size: 0.7rem; color: var(--text-muted); text-transform: uppercase; }
.stat-card.pass .stat-number { color: var(--success); }
.stat-card.fail .stat-number { color: var(--danger); }
.stat-card.na .stat-number { color: var(--neutral); }
.stat-card.unchecked .stat-number { color: var(--warning); }

/* === Failure Cards === */
.failure-card { border-left: 4px solid var(--danger); }
.failure-category { font-size: 0.75rem; color: var(--text-muted); text-transform: uppercase; font-weight: 600; }
.failure-desc { font-weight: 500; margin: 4px 0; }
.failure-notes { font-size: 0.85rem; color: var(--text-muted); font-style: italic; }

.notes-card { white-space: pre-wrap; font-size: 0.9rem; }

/* === Checklist Result === */
.category-heading { margin: 12px 0 8px; color: var(--text-muted); font-size: 0.8rem; text-transform: uppercase; }
.checklist-result-item {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 0;
    border-bottom: 1px solid var(--border);
    font-size: 0.9rem;
}
.result-icon { width: 20px; text-align: center; font-weight: bold; }
.checklist-result-item.pass .result-icon { color: var(--success); }
.checklist-result-item.fail .result-icon { color: var(--danger); }
.checklist-result-item.notapplicable .result-icon { color: var(--neutral); }
.checklist-result-item.notchecked .result-icon { color: var(--warning); }

/* === Error UI === */
#blazor-error-ui {
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}
#blazor-error-ui .dismiss {
    cursor: pointer;
    position: absolute;
    right: 0.75rem;
    top: 0.5rem;
}

