using System.Collections.Concurrent;
using SiteInspector.Shared.Models;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddSingleton<InMemoryStore>();

var app = builder.Build();

// Serve the Blazor WASM client
app.UseStaticFiles();
app.UseBlazorFrameworkFiles();

app.MapPost("/api/sync", (SyncPayload payload, InMemoryStore store) =>
{
    try
    {
        foreach (var site in payload.Sites)
            store.Sites[site.Id] = site;

        foreach (var inspection in payload.Inspections)
        {
            inspection.IsSynced = true;
            store.Inspections[inspection.Id] = inspection;
        }

        return Results.Ok(new SyncResult
        {
            Success = true,
            SitesSynced = payload.Sites.Count,
            InspectionsSynced = payload.Inspections.Count
        });
    }
    catch (Exception ex)
    {
        return Results.Ok(new SyncResult { Success = false, Error = ex.Message });
    }
});

app.MapGet("/api/sites", (InMemoryStore store) =>
    store.Sites.Values.OrderByDescending(s => s.CreatedAt).ToList());

app.MapGet("/api/inspections/{siteId}", (string siteId, InMemoryStore store) =>
    store.Inspections.Values.Where(i => i.SiteId == siteId).OrderByDescending(i => i.InspectedAt).ToList());

app.MapFallbackToFile("index.html");

app.Run();

public class InMemoryStore
{
    public ConcurrentDictionary<string, ConstructionSite> Sites { get; } = new();
    public ConcurrentDictionary<string, Inspection> Inspections { get; } = new();
}

